import 'package:flutter/material.dart';
import 'package:mobileapp/call_log.dart';

class DynamicList extends StatefulWidget {
  const DynamicList({super.key});

  @override
  State<DynamicList> createState() => _DynamicListState();
}

class _DynamicListState extends State<DynamicList> {
  var Car = [
    {
      "name" : "Corolla",
      "model" : "A5",
      "color" : "red",
      "price" : "5600000",
      "image" : "data:image/jpeg;base64,"
    },
    {
      "name" : "Prius",
      "model" : "P3",
      "color" : "white",
      "price" : "7900000",
      "image" : "data:image/jpeg;base64,"
    },
    {
      "name" : "LandCruiser",
      "model" : "L3",
      "color" : "black",
      "price" : "23000000",
      "image" : "data:image/jpeg;base64,"
    },
    {
      "name" : "BMW",
      "model" : "B3",
      "color" : "white",
      "price" : "12000000",
      "image" : "data:image/jpeg;base64,"
    }
  ];
  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(
        title: Text("Cars"),
        centerTitle: true,
        foregroundColor: Colors.white,
        backgroundColor: Colors.black,
      ),
      body: Center(
        child: ListView.builder(
          itemCount: Car.length,
          itemBuilder: (context, index){
            return Padding(
              padding: EdgeInsets.all(10),
              child: ListTile(
                title: Text('${Car[index]['name']}'),
                subtitle: Row(
                  crossAxisAlignment: CrossAxisAlignment.start,
                  children: [
                    Text('${Car[index]['color']} '),
                    Text('${Car[index]['model']}'),
                  ],
                ),
                leading: Image.network('${Car[index]['image']}'),
                trailing: Column(
                  crossAxisAlignment: CrossAxisAlignment.end,
                  children: [
                    Text('${Car[index]['price']}'),
                    IconButton(
                      onPressed: (){
                        Navigator.push(context, MaterialPageRoute(builder: (context){
                          return CallLog();
                        }));
                      },
                      icon: Text('Go To Call Log'))
                  ],
                )
              ),
              ); 
          }),

      ),
    );
  }
}